import React, { useState, useEffect } from 'react';
import {
  Box,
  Container,
  Typography,
  Button,
  Grid,
  Card,
  CardContent,
  Divider,
  Avatar,
  Chip,
  IconButton,
  Menu,
  MenuItem,
  TextField,
  InputAdornment,
  Tabs,
  Tab,
  Skeleton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions
} from '@mui/material';
import { Link as RouterLink } from 'react-router-dom';
import AddIcon from '@mui/icons-material/Add';
import SearchIcon from '@mui/icons-material/Search';
import MoreVertIcon from '@mui/icons-material/MoreVert';
import VerifiedIcon from '@mui/icons-material/Verified';
import PendingIcon from '@mui/icons-material/Pending';
import ContentCopyIcon from '@mui/icons-material/ContentCopy';
import CloseIcon from '@mui/icons-material/Close';
import ShareIcon from '@mui/icons-material/Share';
import TwitterIcon from '@mui/icons-material/Twitter';
import FacebookIcon from '@mui/icons-material/Facebook';
import LinkedInIcon from '@mui/icons-material/LinkedIn';
import { useTheme } from '@mui/material/styles';
import TestimonialWidget from '../components/testimonials/TestimonialWidget';
import TestimonialTemplate from '../components/testimonials/TestimonialTemplate';

const DashboardPage = () => {
  const theme = useTheme();
  const [testimonials, setTestimonials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [tabValue, setTabValue] = useState(0);
  const [anchorEl, setAnchorEl] = useState(null);
  const [selectedTestimonial, setSelectedTestimonial] = useState(null);
  const [showWidget, setShowWidget] = useState(false);
  const [showShare, setShowShare] = useState(false);
  const [shareTemplate, setShareTemplate] = useState('quote');

  // Simulate fetching testimonials
  useEffect(() => {
    setTimeout(() => {
      setTestimonials([
        {
          id: '1',
          clientName: 'Michael Thompson',
          clientTitle: 'Marketing Director',
          clientCompany: 'Acme Inc.',
          original: 'The coaching was good. I learned some things that helped me.',
          enhanced: 'Working with this coach transformed how I approach challenges. I went from feeling stuck to landing two major clients in just 3 weeks. The coaching didnt just teach me tactics—it changed my entire mindset about whats possible.',
          status: 'verified',
          date: '2023-05-15',
          industry: 'Coaching',
          rating: 5
        },
        {
          id: '2',
          clientName: 'Jessica Kim',
          clientTitle: 'Creative Director',
          clientCompany: 'Design Studio',
          original: 'They built a nice website for me. It works well.',
          enhanced: 'The team at DesignPro delivered beyond my expectations. My new website has increased conversions by 43% in the first month alone. Their attention to detail and strategic approach to UX completely transformed my online presence.',
          status: 'pending',
          date: '2023-05-10',
          industry: 'Web Design',
          rating: 4
        },
        {
          id: '3',
          clientName: 'David Rodriguez',
          clientTitle: 'Fitness Enthusiast',
          clientCompany: 'Fitness First',
          original: 'Good trainer. I lost some weight and feel better.',
          enhanced: 'After 3 months with Alex, Ive lost 28 pounds and completely transformed my relationship with fitness. His personalized approach addressed my specific challenges, and for the first time in my life, I actually look forward to my workouts!',
          status: 'verified',
          date: '2023-05-05',
          industry: 'Fitness',
          rating: 5
        }
      ]);
      setLoading(false);
    }, 1000);
  }, []);

  const handleTabChange = (event, newValue) => {
    setTabValue(newValue);
  };

  const handleMenuClick = (event, testimonial) => {
    setAnchorEl(event.currentTarget);
    setSelectedTestimonial(testimonial);
  };

  const handleMenuClose = () => {
    setAnchorEl(null);
  };

  const handleToggleWidget = () => {
    setShowWidget(!showWidget);
    handleMenuClose();
  };

  const handleShareOpen = () => {
    setShowShare(true);
    handleMenuClose();
  };

  const handleShareClose = () => {
    setShowShare(false);
  };

  const handleCopyLink = (testimonial) => {
    const url = `${window.location.origin}/embed/${testimonial.id}`;
    navigator.clipboard.writeText(url);
    // Could add a toast notification here
    handleMenuClose();
  };

  const handleShareSocial = (platform) => {
    const testimonial = selectedTestimonial;
    const text = encodeURIComponent(`Check out this testimonial from ${testimonial.clientName}: "${testimonial.enhanced.substring(0, 100)}..."`);
    const url = encodeURIComponent(`${window.location.origin}/embed/${testimonial.id}`);

    let shareUrl = '';
    switch(platform) {
      case 'twitter':
        shareUrl = `https://twitter.com/intent/tweet?text=${text}&url=${url}`;
        break;
      case 'facebook':
        shareUrl = `https://www.facebook.com/sharer/sharer.php?u=${url}`;
        break;
      case 'linkedin':
        shareUrl = `https://www.linkedin.com/sharing/share-offsite/?url=${url}`;
        break;
      default:
        return;
    }

    window.open(shareUrl, '_blank', 'width=600,height=400');
    handleShareClose();
  };

  const filteredTestimonials = testimonials.filter(testimonial => {
    if (tabValue === 0) return true;
    if (tabValue === 1) return testimonial.status === 'verified';
    if (tabValue === 2) return testimonial.status === 'pending';
    return true;
  });

  return (
    <Box sx={{ py: 4 }}>
      <Container maxWidth="lg">
        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 4 }}>
          <Typography variant="h4" fontWeight="bold">Your Testimonials</Typography>

          <Box sx={{ display: 'flex', gap: 2 }}>
            <Tabs value={tabValue} onChange={handleTabChange}>
              <Tab label="All" />
              <Tab label="Verified" />
              <Tab label="Pending" />
            </Tabs>
          </Box>

          <Button
            variant="contained"
            color="primary"
            startIcon={<AddIcon />}
            component={RouterLink}
            to="/enhance"
          >
            New Testimonial
          </Button>
        </Box>

        {loading ? (
          <Grid container spacing={3}>
            {[1, 2, 3].map((item) => (
              <Grid item xs={12} key={item}>
                <Card sx={{ borderRadius: 2 }}>
                  <CardContent>
                    <Box sx={{ display: 'flex', mb: 2 }}>
                      <Skeleton variant="circular" width={40} height={40} sx={{ mr: 2 }} />
                      <Box>
                        <Skeleton variant="text" width={120} />
                        <Skeleton variant="text" width={80} />
                      </Box>
                    </Box>
                    <Skeleton variant="rectangular" height={80} />
                  </CardContent>
                </Card>
              </Grid>
            ))}
          </Grid>
        ) : (
          <>
            {filteredTestimonials.length === 0 ? (
              <Box sx={{ textAlign: 'center', py: 8 }}>
                <Typography variant="h5" gutterBottom>No testimonials found</Typography>
                <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>
                  {tabValue === 0 ? "You haven't created any testimonials yet." : 
                   tabValue === 1 ? "You don't have any verified testimonials yet." :
                   "You don't have any pending testimonials."}
                </Typography>
                {tabValue === 0 && (
                  <Button 
                    variant="contained" 
                    color="primary"
                    startIcon={<AddIcon />}
                    component={RouterLink}
                    to="/enhance"
                  >
                    Create Your First Testimonial
                  </Button>
                )}
              </Box>
            ) : (
              <Grid container spacing={3}>
                {filteredTestimonials.map((testimonial) => (
                  <Grid item xs={12} key={testimonial.id}>
                    <Card 
                      sx={{ 
                        borderRadius: 2,
                        boxShadow: '0 4px 20px rgba(0,0,0,0.08)',
                        transition: 'transform 0.2s ease-in-out',
                        '&:hover': {
                          transform: 'translateY(-4px)',
                          boxShadow: '0 8px 30px rgba(0,0,0,0.12)'
                        }
                      }}
                    >
                      <CardContent>
                        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', mb: 2 }}>
                          <Box sx={{ display: 'flex', alignItems: 'center' }}>
                            <Avatar 
                              sx={{ 
                                bgcolor: theme.palette.primary.main,
                                width: 48,
                                height: 48,
                                mr: 2
                              }}
                            >
                              {testimonial.clientName.charAt(0)}
                            </Avatar>
                            <Box>
                              <Typography variant="h6">{testimonial.clientName}</Typography>
                              <Typography variant="body2" color="text.secondary">
                                {testimonial.clientTitle}, {testimonial.clientCompany}
                              </Typography>
                            </Box>
                          </Box>

                          <Box sx={{ display: 'flex', alignItems: 'center' }}>
                            {testimonial.status === 'verified' ? (
                              <Chip 
                                icon={<VerifiedIcon />} 
                                label="Verified" 
                                color="success" 
                                size="small"
                                sx={{ mr: 1 }}
                              />
                            ) : (
                              <Chip 
                                icon={<PendingIcon />} 
                                label="Pending" 
                                color="warning" 
                                size="small"
                                sx={{ mr: 1 }}
                              />
                            )}

                            <IconButton
                              aria-label="more"
                              onClick={(e) => handleMenuClick(e, testimonial)}
                            >
                              <MoreVertIcon />
                            </IconButton>
                          </Box>
                        </Box>

                        <Divider sx={{ my: 2 }} />

                        <Box sx={{ mb: 2 }}>
                          <Typography variant="body2" color="text.secondary" gutterBottom>
                            Original
                          </Typography>
                          <Typography variant="body1">
                            {testimonial.original}
                          </Typography>
                        </Box>

                        <Box>
                          <Typography variant="body2" color="text.secondary" gutterBottom>
                            Enhanced
                          </Typography>
                          <Typography variant="body1">
                            {testimonial.enhanced}
                          </Typography>
                        </Box>
                      </CardContent>
                    </Card>
                  </Grid>
                ))}
              </Grid>
            )}
          </>
        )}

        <Menu
          anchorEl={anchorEl}
          open={Boolean(anchorEl)}
          onClose={handleMenuClose}
        >
          <MenuItem onClick={handleToggleWidget}>
            <ContentCopyIcon fontSize="small" sx={{ mr: 1 }} />
            Embed Widget
          </MenuItem>
          <MenuItem onClick={handleShareOpen}>
            <ShareIcon fontSize="small" sx={{ mr: 1 }} />
            Share on Social
          </MenuItem>
          <MenuItem onClick={() => handleCopyLink(selectedTestimonial)}>
            <ContentCopyIcon fontSize="small" sx={{ mr: 1 }} />
            Copy Link
          </MenuItem>
        </Menu>

        {showWidget && selectedTestimonial && (
          <Dialog
            open={showWidget}
            onClose={() => setShowWidget(false)}
            maxWidth="md"
            fullWidth
          >
            <DialogTitle>
              Embed Testimonial Widget
              <IconButton
                aria-label="close"
                onClick={() => setShowWidget(false)}
                sx={{ position: 'absolute', right: 8, top: 8 }}
              >
                <CloseIcon />
              </IconButton>
            </DialogTitle>
            <DialogContent>
              <TestimonialWidget 
                testimonials={[selectedTestimonial]}
                onCopy={() => {
                  // Show success message or notification
                }}
              />
            </DialogContent>
          </Dialog>
        )}

        {showShare && selectedTestimonial && (
          <Dialog
            open={showShare}
            onClose={handleShareClose}
            maxWidth="md"
            fullWidth
          >
            <DialogTitle>
              Share Testimonial
              <IconButton
                aria-label="close"
                onClick={handleShareClose}
                sx={{ position: 'absolute', right: 8, top: 8 }}
              >
                <CloseIcon />
              </IconButton>
            </DialogTitle>
            <DialogContent>
              <Box sx={{ mb: 3 }}>
                <Typography variant="subtitle1" gutterBottom>Preview</Typography>
                <TestimonialTemplate
                  type={shareTemplate}
                  text={selectedTestimonial.enhanced}
                  clientName={selectedTestimonial.clientName}
                  clientTitle={selectedTestimonial.clientTitle}
                  companyName={selectedTestimonial.clientCompany}
                  rating={selectedTestimonial.rating}
                  verified={selectedTestimonial.status === 'verified'}
                />
              </Box>

              <Typography variant="subtitle1" gutterBottom>Share on</Typography>
              <Box sx={{ display: 'flex', gap: 2 }}>
                <Button 
                  variant="outlined" 
                  startIcon={<TwitterIcon />}
                  onClick={() => handleShareSocial('twitter')}
                  sx={{ borderRadius: 2 }}
                >
                  Twitter
                </Button>
                <Button 
                  variant="outlined" 
                  startIcon={<FacebookIcon />}
                  onClick={() => handleShareSocial('facebook')}
                  sx={{ borderRadius: 2 }}
                >
                  Facebook
                </Button>
                <Button 
                  variant="outlined" 
                  startIcon={<LinkedInIcon />}
                  onClick={() => handleShareSocial('linkedin')}
                  sx={{ borderRadius: 2 }}
                >
                  LinkedIn
                </Button>
              </Box>
            </DialogContent>
            <DialogActions>
              <Button onClick={handleShareClose}>Cancel</Button>
              <Button 
                variant="contained" 
                onClick={() => {
                  const url = `${window.location.origin}/embed/${selectedTestimonial.id}`;
                  navigator.clipboard.writeText(url);
                  // Could add a toast notification here
                }}
              >
                Copy Link
              </Button>
            </DialogActions>
          </Dialog>
        )}
      </Container>
    </Box>
  );
};

export default DashboardPage;
